using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a weather REST API via HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI and does NOT expose them in the tool schema.
/// </summary>
[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };

    [McpServerTool, Description("Get the current weather for a city. Returns temperature, humidity, and conditions.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'London' or 'New York'")] string city,
        [Description("Temperature unit: 'celsius' or 'fahrenheit' (default: celsius)")] string units = "celsius",
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching current weather for {City}", city);

        var response = await httpClient.GetAsync(
            $"/v1/weather/current?city={Uri.EscapeDataString(city)}&units={Uri.EscapeDataString(units)}",
            cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Tokyo'")] string city,
        [Description("Number of days to forecast (1–7, default: 3)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching {Days}-day forecast for {City}", days, city);

        var response = await httpClient.GetAsync(
            $"/v1/weather/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = true), Description("Search for cities matching a query. Use this to find exact city names before calling weather tools.")]
    public async Task<string> SearchCities(
        [Description("Partial city name to search for")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching cities matching '{Query}'", query);

        var response = await httpClient.GetAsync(
            $"/v1/cities/search?q={Uri.EscapeDataString(query)}",
            cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

