using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// All logs must go to stderr — stdout carries the MCP JSON-RPC protocol.
builder.Logging.AddConsole(o => o.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient with a base address for the weather API.
// The SDK injects this into WeatherTools via constructor injection.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.weatherservice.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();   // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();

